export function initialize(sentinelElement, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        }
    }, { rootMargin: '0px 0px 200px 0px' });

    observer.observe(sentinelElement);

    return observer;
}

export function dispose(observer, sentinelElement) {
    observer.unobserve(sentinelElement);
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether more items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when the user scrolls near the bottom.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
            observer = await module.InvokeAsync<IJSObjectReference>(
                "initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null && observer is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose", observer, sentinelRef);
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit is gone — nothing to clean up on the client.
            }
        }

        dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.15);
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

